2118	    /// `check_step` (collect only if heap byte threshold exceeded).
2119	    ///
2120	    /// Snapshots the weak-tables registry, invokes the heap's collect path
2121	    /// with a post-mark weak-prune hook, and rebuilds the registry by
2122	    /// retaining only entries whose target was reachable. The same hook
2123	    /// works for both modes — the heap short-circuits when force=false and
2124	    /// the threshold isn't met.
2125	    fn collect_via_heap(&self, force: bool) {
2126	        let state_ref: &LuaState = &*self._state;
2127	
2128	        // Snapshot weak tables BEFORE the collect. `identity()` reads only
2129	        // the pointer address — safe even on still-dangling weak handles —
2130	        // and dedup by identity keeps the iteration linear.
2131	        let weak_tables_snapshot: Vec<lua_types::gc::GcRef<lua_types::value::LuaTable>> = {
2132	            let g = state_ref.global.borrow();
2133	            let mut seen = std::collections::HashSet::<usize>::new();
2134	            g.weak_tables_registry
2135	                .iter()
2136	                .filter_map(|w| w.upgrade())
2137	                .filter(|t| seen.insert(t.identity()))
2138	                .collect()
2139	        };
2140	
2141	        let alive_ids: std::cell::RefCell<std::collections::HashSet<usize>> =
2142	            std::cell::RefCell::new(std::collections::HashSet::new());
2143	        let collect_ran = std::cell::Cell::new(false);
2144	
2145	        {
2146	            let global = state_ref.global.borrow();
2147	            global.heap.unpause();
2148	            let roots = CollectRoots { global: &*global, thread: state_ref };
2149	            let hook = |is_reachable: &dyn Fn(usize) -> bool| {
2150	                collect_ran.set(true);
2151	                for t in &weak_tables_snapshot {
2152	                    let id = t.identity();
2153	                    if is_reachable(id) {
2154	                        t.prune_weak_dead(is_reachable);
